    const putOI = chain.put?.oi ?? 0;

    // GEX = OI × gamma × S² × multiplier / 100
    const gexFactor = bs.gamma * spot * spot * multiplier / 100;
    const callGex = callOI * gexFactor;
    const putGex = -(putOI * gexFactor);
