      criticalAbove: typeof r.criticalAbove === "number" ? r.criticalAbove : undefined,
      warnBelow: typeof r.warnBelow === "number" ? r.warnBelow : undefined,
      criticalBelow: typeof r.criticalBelow === "number" ? r.criticalBelow : undefined,
