const quotes_log = logService.namespace("network");
function fetchQuotes(symbols, token) {
  const equitySymbols = symbols.filter(s => !isOptionSymbol(s));
  const skippedOptions = symbols.length - equitySymbols.length;
  if (skippedOptions > 0) {
    quotes_log.debug("fetchQuotes.optionsSkipped", {
      count: skippedOptions
    });
  }
  if (equitySymbols.length === 0) {
    return Promise.resolve({
      quotes: []
    });
  }
  const span = quotes_log.span("fetchQuotes", {
    symbolCount: equitySymbols.length
  });
  const url = `https://ausgateway.schwab.com/api/is.ResearchExperience/v1/quote?symbols=${encodeURIComponent(equitySymbols.join(","))}&requesttype=basic`;
  const doRequest = async bearerToken => {
    const response = await fetch(url, {
      method: "GET",
      headers: {
        Accept: "application/json",
        "Content-Type": "application/json",
        Authorization: "Bearer " + bearerToken,
        "Schwab-Client-Channel": "IO",
        "Schwab-Env": "PROD",
        "Schwab-Client-CorrelId": generateUUID(),
        "Schwab-Resource-Version": "2"
      }
    });
    if (response.status === 401) {
      await throw401(response);
    }
    return response.json();
  };
  return withTokenRefresh(doRequest, token).then(d => computeWorkerPool.parseQuotes(d)).then(result => {
    span.end("ok", {
      quoteCount: result.quotes.length
    }, "debug");
    return result;
  }).catch(err => {
    span.end("error", {
      error: err?.message ?? String(err)
    }, "error");
    throw err;
  });
}
