const yahoo_httpUtils_log = logService.namespace("network");
function extractDomain(url) {
  try {
    return new URL(url).hostname;
  } catch {
    return url.slice(0, 60);
  }
}

// GM.xmlHttpRequest type declaration (Tampermonkey TM4 API)

function gmGetWithHeaders(url, headers, timeoutMs = 30_000) {
  const domain = extractDomain(url);
  yahoo_httpUtils_log.debug("http.get", {
    domain
  });
  return new Promise((resolve, reject) => {
    GM.xmlHttpRequest({
      method: "GET",
      url,
      headers,
      timeout: timeoutMs,
      onload: resp => {
        if (resp.status >= 400) {
          yahoo_httpUtils_log.warn("http.get", {
            domain,
            status: resp.status
          });
          reject(new Error(`HTTP ${resp.status}: ${url}`));
          return;
        }
        resolve(resp.responseText);
      },
      onerror: () => {
        yahoo_httpUtils_log.warn("http.get", {
          domain,
          error: "network_error"
        });
        reject(new Error(`Network error fetching: ${url}`));
      },
      ontimeout: () => {
        yahoo_httpUtils_log.warn("http.get", {
          domain,
          error: "timeout",
          timeoutMs
        });
        reject(new Error(`Timeout fetching: ${url}`));
      }
    });
  });
}
function gmGet(url, timeoutMs = 30_000) {
  return gmGetWithHeaders(url, {
    Accept: "application/json",
    "User-Agent": "Mozilla/5.0"
  }, timeoutMs);
}
