const sharedDOMParser = new DOMParser();
function parseNewsSearchHtml(html) {
  const results = [];
  try {
    const doc = sharedDOMParser.parseFromString(html, "text/html");
    const rows = doc.querySelectorAll(".news-item, .newsItem, tr[data-dockey]");
    for (const row of rows) {
      const headline = row.querySelector(".headline, .title, a")?.textContent?.trim() ?? "";
      if (!headline) continue;
      const source = row.querySelector(".source, .provider")?.textContent?.trim() ?? "";
      const dateTime = row.querySelector(".date, .dateTime, time")?.textContent?.trim() ?? "";
      const docKey = row.getAttribute("data-dockey") ?? row.querySelector("a")?.getAttribute("data-dockey") ?? row.querySelector("a")?.getAttribute("href") ?? "";
      const summary = row.querySelector(".summary, .snippet, .desc")?.textContent?.trim() ?? "";
      results.push({
        headline,
        source,
        dateTime,
        docKey,
        summary
      });
    }
  } catch {
    // Fail-soft: return empty on parse error
  }
  return results;
}
