function getProviderApiKey(config) {
  switch (config.selected) {
    case "anthropic":
      return config.anthropic.apiKey;
    case "openai":
      return config.openai.apiKey;
    case "google":
      return config.google.apiKey;
    default:
      return "";
  }
}
