// Bridges holdings symbol scope into the shared NewsService lifecycle.
class NewsLifecycleCoordinator {
  started = false;
  constructor(logger) {
    this.logger = logger;
  }
  start(initialSymbols) {
    if (this.started) {
      newsService.updateSymbols(initialSymbols);
      return;
    }
    this.started = true;
    newsService.start(initialSymbols);
    this.logger.info("started", {
      symbolCount: initialSymbols.length
    });
  }
  stop() {
    if (!this.started) return;
    newsService.stop();
    this.started = false;
    this.logger.info("stopped");
  }
  handleSymbolDelta(delta) {
    if (!this.started) {
      this.start(delta.all);
      return;
    }
    newsService.updateSymbols(delta.all);
  }
}
