// ── Internal config types ───────────────────────────────────────────────────

const HORIZONS = [{
  key: "ultraShort",
  label: "1D",
  days: 5,
  interval: "5m"
}, {
  key: "week",
  label: "1W",
  days: 12,
  interval: "5m"
}, {
  key: "short",
  label: "1M",
  days: 35,
  interval: "15m"
}, {
  key: "medium",
  label: "6M",
  days: 200,
  interval: "1h"
}, {
  key: "long",
  label: "2Y",
  days: 760,
  interval: "1d"
}];
// ── Shared horizon loop helper ──────────────────────────────────────────────

/** Compute a per-horizon result across all horizons in parallel, catching errors per horizon. */
async function computeAcrossHorizons(symbol, computeOne, logTag) {
  const entries = await Promise.all(HORIZONS.map(async horizon => {
    try {
      return [horizon.key, await computeOne(horizon)];
    } catch (err) {
      betaHorizons_log.warn(logTag, {
        symbol,
        horizon: horizon.key,
        error: err?.message
      });
      return [horizon.key, null];
    }
  }));
  return Object.fromEntries(entries);
}
