// Centralized layout-mode detection for CSS class toggles and JS branching.

let current = "desktop";
const layoutMode_listeners = new Set();

/** Initialize layout detection and keep it reactive on viewport changes. */
function initLayoutMode() {
  const mql = window.matchMedia("(max-width: 768px)");
  current = mql.matches ? "mobile" : "desktop";
  applyHtmlClass(current);
  mql.addEventListener("change", e => {
    const next = e.matches ? "mobile" : "desktop";
    if (next === current) return;
    current = next;
    applyHtmlClass(current);
    layoutMode_listeners.forEach(fn => fn(current));
  });
  return current;
}

/** Synchronous read of current layout mode. */
function getLayoutMode() {
  return current;
}

/** Subscribe to layout mode changes. Returns an unsubscribe function. */
function onLayoutModeChange(fn) {
  layoutMode_listeners.add(fn);
  return () => {
    layoutMode_listeners.delete(fn);
  };
}
function applyHtmlClass(mode) {
  document.documentElement.classList.toggle("layout-mobile", mode === "mobile");
  document.documentElement.classList.toggle("layout-desktop", mode === "desktop");
}
;// ./src/shared/utils/format/relativeTime.ts
function formatTimeAgo(isoString, options = {}) {
  const timestamp = new Date(isoString).getTime();
  if (!Number.isFinite(timestamp)) return "—";
  const nowMs = options.nowMs ?? Date.now();
  const diffMs = Math.max(0, nowMs - timestamp);
  const mins = Math.floor(diffMs / 60_000);
  const includeJustNow = options.includeJustNow !== false;
  if (mins < 1 && includeJustNow) return "just now";
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs / 24)}d ago`;
}
