// ── Copy with flash feedback ───────────────────────────────────────────────
// Unified copy-to-clipboard with button flash, replacing 3 duplicate patterns.

async function copyWithFlash(btn, getText) {
  const text = getText();
  if (!text) return;
  const ok = await ui_copyTextToClipboard(text);
  const origHTML = btn.innerHTML;
  btn.innerHTML = ok ? '<span style="font-size:13px">\u2705</span><span>Copied!</span>' : '<span style="font-size:13px">\u274C</span><span>Failed</span>';
  setTimeout(() => {
    btn.innerHTML = origHTML;
  }, 1500);
}

