function createStabilityWarnings(scenarios, modelType) {
  if (modelType !== "threeFactor") return null;
  if (scenarios.length === 0) return null;
  const warnings = [];
  const allPositions = scenarios[0].positions;
  const tfPositions = allPositions.filter(p => p.modelUsed === "threeFactor");
  const ancFallback = allPositions.filter(p => p.modelUsed === "anchor");
  if (tfPositions.length === 0) {
    // No 3-factor positions are active — primary warning is shown in banner.
    return null;
  }
  if (ancFallback.length > 0 && tfPositions.length > 0) {
    warnings.push(`${ancFallback.length} position(s) fell back to anchor β (no 3-factor data).`);
  }
  if (tfPositions.length > 0) {
    const smallSample = tfPositions.filter(p => p.sampleSize < 30);
    if (smallSample.length > 0) {
      warnings.push(`${smallSample.length} position(s) with <30 data points — factor estimates may be unstable.`);
    }
    const lowR2 = tfPositions.filter(p => p.rSquared < 0.15);
    if (lowR2.length > 0) {
      warnings.push(`${lowR2.length} position(s) with R²<15% — model explains little variance.`);
    }
    const highResidual = tfPositions.filter(p => p.residualStd > 0.05);
    if (highResidual.length > 0) {
      warnings.push(`${highResidual.length} position(s) with high residual volatility (>5%/day).`);
    }
  }
  if (scenarios[0].coveredPct < 0.70) {
    warnings.push(`Only ${(scenarios[0].coveredPct * 100).toFixed(0)}% of notional is covered by the model.`);
  }
  if (warnings.length === 0) return null;
  const warnColors = ds_severityColors("warning");
  const container = createElement_ui_createElement("div", {
    styleString: `font-size: 11px; line-height: 1.4; padding: 6px 10px; border-radius: 8px;` + ` background: ${warnColors.bg}; border: 1px solid ${warnColors.border};` + ` color: ${warnColors.text}; margin-top: 8px;`
  });
  container.appendChild(createElement_ui_createElement("div", {
    text: "Stability Warnings",
    styleString: "font-weight: 700; margin-bottom: 3px;"
  }));
  for (const w of warnings) {
    container.appendChild(createElement_ui_createElement("div", {
      text: `• ${w}`,
      styleString: "margin-left: 4px;"
    }));
  }
  return container;
}
