  // Pct limits are ratios 0–1 (e.g. 0.75 = 75%)
  const defaultRiskLimits = {
    maxMarginUtilizationPct: 0.75,
    maxBeta: 1.2,
    maxSingleUnderlyingDeltaPct: 0.30,
    maxSingleUnderlyingMarketValuePct: 0.40,
    maxNetDeltaShares: 5000,
    maxAbsVegaPerVolPoint: 10000,
    maxDailyLossPct: 0.05,
    maxDailyLossDollar: 5000
  };
  const riskLimitsModal = createSettingsJsonEditorModal({
    title: "Risk Limits",
    description: "Configure risk limits for monitoring and alerts. All limits are optional.",
    getValue: () => settings.riskLimits ? JSON.stringify(settings.riskLimits, null, 2) : JSON.stringify(defaultRiskLimits, null, 2),
    validate: raw => {
      try {
        const parsed = JSON.parse(raw || "{}");
        if (!parsed || typeof parsed !== "object") return "Invalid JSON: root must be an object";
        return null;
      } catch (e) {
        return `Invalid JSON: ${e?.message ?? String(e)}`;
      }
    },
    onApply: raw => {
      ctx.onUpdateSettings({
        riskLimits: JSON.parse(raw)
      });
    }
  });
  wrap.appendChild(riskLimitsModal.backdrop);
