// ── Legacy types (kept for backward compatibility with optionFlow) ──────────

// ── Panel style ─────────────────────────────────────────────────────────────

const PANEL_STYLE = theme_DS_COMPONENTS.panel + " display: flex; flex-direction: column; height: 100%; overflow: hidden;";
