function createSpotPlugin(getPrice, getLabels) {
  return {
    id: "spotLine",
    afterDraw: chart => {
      const price = getPrice();
      const labels = getLabels();
      if (price == null || labels.length === 0) return;
      const {
        ctx: c,
        chartArea,
        scales
      } = chart;
      if (!chartArea || !scales.x) return;
      let bestIdx = 0;
      let bestDiff = Infinity;
      for (let i = 0; i < labels.length; i++) {
        const diff = Math.abs(Number(labels[i]) - price);
        if (diff < bestDiff) {
          bestDiff = diff;
          bestIdx = i;
        }
      }
      const xPixel = scales.x.getPixelForValue(labels[bestIdx]);
      if (xPixel < chartArea.left || xPixel > chartArea.right) return;
      c.save();
      c.setLineDash([6, 4]);
      c.lineWidth = 1.5;
      c.strokeStyle = OPTIONS_SEMANTIC_COLORS.spot;
      c.beginPath();
      c.moveTo(xPixel, chartArea.top);
      c.lineTo(xPixel, chartArea.bottom);
      c.stroke();
      c.setLineDash([]);
      c.fillStyle = OPTIONS_SEMANTIC_COLORS.spot;
      c.font = CHART_FONTS.label;
      c.textAlign = "center";
      c.textBaseline = "bottom";
      c.fillText("Spot", xPixel, chartArea.top - 3);
      c.restore();
    }
  };
}
;// ./src/frontend/analysis_options/focus/focusStrikeOverlayPlugin.ts

function createVerticalFocusStrikePlugin(getFocusedLevels, getLabels) {
  return {
    id: "focusStrikeVertical",
    afterDraw: chart => {
      const levels = getFocusedLevels();
      const labels = getLabels();
      if (levels.length === 0 || labels.length === 0) return;
      const {
        ctx,
        chartArea,
        scales
      } = chart;
      if (!ctx || !chartArea || !scales?.x) return;
      const items = [];
      for (const lvl of levels) {
        let bestIdx = 0;
        let bestDiff = Infinity;
        for (let i = 0; i < labels.length; i++) {
          const diff = Math.abs(Number(labels[i]) - lvl.strike);
          if (diff < bestDiff) {
            bestDiff = diff;
            bestIdx = i;
          }
        }
        const xPixel = scales.x.getPixelForValue(labels[bestIdx]);
        if (!isFinite(xPixel) || xPixel < chartArea.left || xPixel > chartArea.right) continue;
        items.push({
          lvl,
          xPixel
        });
      }
      items.sort((a, b) => a.xPixel - b.xPixel);
      ctx.save();
      ctx.font = CHART_FONTS.label;
      const yOffsets = [];
      for (let i = 0; i < items.length; i++) {
        let tier = 0;
        const halfWidthI = ctx.measureText(items[i].lvl.label).width / 2 + 2;
        for (let attempt = 0; attempt < 4; attempt++) {
          let collision = false;
          for (let j = 0; j < i; j++) {
            if (yOffsets[j] !== tier) continue;
            const halfWidthJ = ctx.measureText(items[j].lvl.label).width / 2 + 2;
            if (Math.abs(items[i].xPixel - items[j].xPixel) < halfWidthI + halfWidthJ) {
              collision = true;
              break;
            }
          }
          if (!collision) break;
          tier++;
        }
        yOffsets.push(tier);
      }
      ctx.restore();
      for (let i = 0; i < items.length; i++) {
        const {
          lvl,
          xPixel
        } = items[i];
        ctx.save();
        ctx.setLineDash([2, 3]);
        ctx.lineWidth = 1;
        ctx.strokeStyle = lvl.color;
        ctx.beginPath();
        ctx.moveTo(xPixel, chartArea.top);
        ctx.lineTo(xPixel, chartArea.bottom);
        ctx.stroke();
        ctx.setLineDash([]);
        ctx.fillStyle = lvl.color;
        ctx.font = CHART_FONTS.label;
        ctx.textAlign = "center";
        ctx.textBaseline = "bottom";
        ctx.fillText(lvl.label, xPixel, chartArea.top - 2 - yOffsets[i] * 12);
        ctx.restore();
      }
    }
  };
}
;// ./src/frontend/analysis_options/components/charts/IVSkew.ts








// ── 25-delta put skew slope annotation plugin ────────────────────────────────

function createSlopeAnnotationPlugin(getData, getPrice) {
  return {
    id: "skewSlope",
    afterDatasetsDraw: chart => {
      const price = getPrice();
      const data = getData();
      if (price == null || price <= 0 || data.length < 4) return;
      const {
        ctx,
        chartArea,
        scales
      } = chart;
      if (!chartArea || !scales.x || !scales.y) return;

      // Find strikes in ~90-97% moneyness range (rough 25-delta put region)
      const region = data.filter(d => {
        const m = d.strike / price;
        return m >= 0.9 && m <= 0.97 && d.putIV != null;
      });
      if (region.length < 2) return;

      // Linear regression: slope of putIV vs moneyness%
      const xs = region.map(d => d.strike / price * 100);
      const ys = region.map(d => d.putIV);
      const n = xs.length;
      const sumX = xs.reduce((s, v) => s + v, 0);
      const sumY = ys.reduce((s, v) => s + v, 0);
      const sumXY = xs.reduce((s, v, i) => s + v * ys[i], 0);
      const sumXX = xs.reduce((s, v) => s + v * v, 0);
      const denom = n * sumXX - sumX * sumX;
      if (Math.abs(denom) < 1e-12) return;
      const slope = (n * sumXY - sumX * sumY) / denom;
      const intercept = (sumY - slope * sumX) / n;

      // Draw tangent line through the 25-delta region
      const labels = chart.data.labels;
      const startStrike = region[0].strike;
      const endStrike = region[region.length - 1].strike;
      let startIdx = -1;
      let endIdx = -1;
      for (let i = 0; i < labels.length; i++) {
        const s = Number(labels[i]);
        if (startIdx < 0 && s >= startStrike) startIdx = i;
        if (s <= endStrike) endIdx = i;
      }
      if (startIdx < 0 || endIdx < 0 || startIdx >= endIdx) return;
      const xPx1 = scales.x.getPixelForValue(startIdx);
      const xPx2 = scales.x.getPixelForValue(endIdx);
      const m1 = startStrike / price * 100;
      const m2 = endStrike / price * 100;
      const yVal1 = slope * m1 + intercept;
      const yVal2 = slope * m2 + intercept;
      const yPx1 = scales.y.getPixelForValue(yVal1);
      const yPx2 = scales.y.getPixelForValue(yVal2);
      ctx.save();
      ctx.strokeStyle = "rgba(88, 86, 214, 0.6)";
      ctx.lineWidth = 2;
      ctx.setLineDash([6, 3]);
      ctx.beginPath();
      ctx.moveTo(xPx1, yPx1);
      ctx.lineTo(xPx2, yPx2);
      ctx.stroke();

      // Badge label at midpoint
      ctx.setLineDash([]);
      const midX = (xPx1 + xPx2) / 2;
      const midY = (yPx1 + yPx2) / 2;
      const text = `25\u0394 slope: ${slope.toFixed(2)}%/1%`;
      ctx.font = "600 9px -apple-system, BlinkMacSystemFont, sans-serif";
      const tw = ctx.measureText(text).width;
      const bW = tw + 8;
      const bH = 14;
      const bX = midX - bW / 2;
      const bY = midY - bH - 4;
      ctx.fillStyle = "rgba(88, 86, 214, 0.12)";
      ctx.beginPath();
      ctx.roundRect(bX, bY, bW, bH, 3);
      ctx.fill();
      ctx.fillStyle = DS_COLORS.raw.purple;
      ctx.textAlign = "center";
      ctx.textBaseline = "middle";
      ctx.fillText(text, midX, bY + bH / 2);
      ctx.restore();
    }
  };
}
