function pickSide(d, atmStrike) {
  return d.strike > atmStrike ? "call" : "put";
}
function PricingAnalysis_spreadPct(bid, ask) {
  if (bid == null || ask == null || bid <= 0 || ask <= 0) return null;
  const mid = (bid + ask) / 2;
  if (mid <= 0) return null;
  return (ask - bid) / mid; // ratio 0–1
}
function PricingAnalysis_midPrice(bid, ask) {
  if (bid == null || ask == null || bid <= 0 || ask <= 0) return null;
  return (bid + ask) / 2;
}
