function detectInversions(ts) {
  const inversions = [];
  const sorted = [...ts].filter(p => p.avgIV != null).sort((a, b) => a.daysUntil - b.daysUntil);
  for (let i = 0; i < sorted.length - 1; i++) {
    const near = sorted[i];
    const far = sorted[i + 1];
    if (near.avgIV == null || far.avgIV == null) continue;
    const diff = near.avgIV - far.avgIV;
    if (diff > 3) {
      inversions.push({
        exp1: near.label,
        exp2: far.label,
        nearIV: near.avgIV,
        farIV: far.avgIV,
        diff
      });
    }
  }
  return inversions;
}
function formatPercentDisplay(v) {
  return formatPct(v, {
    decimals: 1,
    multiply: false
  });
}
function formatPp(v, showPlus = false) {
  if (v == null || !isFinite(v)) return "--";
  const sign = showPlus && v > 0 ? "+" : "";
  return `${sign}${v.toFixed(1)}pp`;
}
