// ── Helpers ──

function getSelectedExpiration(store) {
  const state = store.getState();
  if (!state.response || state.response.expirations.length === 0) return null;
  return state.response.expirations[state.selectedExpirationIdx] ?? state.response.expirations[0];
}
function buildActiveFilters(store) {
  const state = store.getState();
  return {
    scopeMode: state.scopeMode,
    localWindowMode: state.localWindowMode,
    localWindowPct: state.localWindowPct,
    localWindowDeltaRange: state.localWindowDeltaRange,
    liquidityPreset: state.liquidityPreset,
    greeksBasis: state.greeksBasis,
    gammaSource: state.gammaSource,
    strikeMode: state.strikeMode,
    selectedStrikeCount: state.selectedStrikeCount,
    strikeDollarWidth: state.strikeDollarWidth
  };
}
function buildViewControlsState(store) {
  const state = store.getState();
  return {
    selectedExpirationIdx: state.selectedExpirationIdx,
    customExpirationIdxs: state.customExpirationIdxs,
    scopeMode: state.scopeMode,
    greeksBasis: state.greeksBasis,
    gammaSource: state.gammaSource,
    localWindowMode: state.localWindowMode,
    localWindowPct: state.localWindowPct,
    localWindowDeltaRange: state.localWindowDeltaRange,
    strikeMode: state.strikeMode,
    selectedStrikeCount: state.selectedStrikeCount,
    strikeDollarWidth: state.strikeDollarWidth,
    liquidityPreset: state.liquidityPreset,
    liquidityAdvanced: state.liquidityAdvanced
  };
}
function buildControlCallbacks(deps, store) {
  return {
    onExpirationChange: (idx, customIdxs) => {
      const patch = {
        selectedExpirationIdx: idx
      };
      if (customIdxs) patch.customExpirationIdxs = customIdxs;
      store.setState(patch);
      deps.renderCharts();
    },
    onScopeChange: mode => {
      store.setState({
        scopeMode: mode
      });
      deps.renderCharts();
    },
    onLocalWindowChange: (mode, pct, deltaRange) => {
      store.setState({
        localWindowMode: mode,
        localWindowPct: pct,
        localWindowDeltaRange: deltaRange
      });
      deps.renderCharts();
    },
    onStrikeChange: (mode, count, dollarWidth) => {
      store.setState({
        strikeMode: mode,
        selectedStrikeCount: count,
        strikeDollarWidth: dollarWidth
      });
      deps.renderCharts();
    },
    onLiquidityChange: (preset, advanced) => {
      store.setState({
        liquidityPreset: preset,
        liquidityAdvanced: advanced
      });
      deps.renderCharts();
    },
    onBasisChange: basis => {
      store.setState({
        greeksBasis: basis
      });
      deps.renderCharts();
    },
    onGammaSourceChange: source => {
      store.setState({
        gammaSource: source
      });
      deps.renderCharts();
    }
  };
}
