const store_log = logService.namespace("storage");
function createDashboardStore(initialSymbol) {
  const today = getTodayDateCT();
  let state = {
    symbol: initialSymbol || "SPY",
    dateStart: today,
    dateEnd: today,
    timeStartMin: CAPTURE_WINDOW_MIN,
    timeEndMin: CAPTURE_WINDOW_MAX,
    loading: false,
    error: null,
    metaRows: [],
    expiryRows: []
  };
  const listeners = new Set();
  function notify() {
    for (const fn of listeners) {
      try {
        fn(state);
      } catch (e) {
        store_log.warn("store.listener.error", {
          error: e?.message ?? String(e)
        });
      }
    }
  }
  return {
    getState: () => state,
    setSymbol(symbol) {
      state = {
        ...state,
        symbol
      };
      notify();
    },
    setDateRange(dateStart, dateEnd) {
      state = {
        ...state,
        dateStart,
        dateEnd
      };
      notify();
    },
    setTimeWindow(startMin, endMin) {
      state = {
        ...state,
        timeStartMin: startMin,
        timeEndMin: endMin
      };
      notify();
    },
    setLoading(loading) {
      state = {
        ...state,
        loading
      };
      notify();
    },
    setError(error) {
      state = {
        ...state,
        error
      };
      notify();
    },
    update(patch) {
      state = {
        ...state,
        ...patch
      };
      notify();
    },
    subscribe(listener) {
      listeners.add(listener);
      return () => {
        listeners.delete(listener);
      };
    }
  };
}
