    const rows = await this.getByOpeningId(openingId);
    if (rows.length === 0) return;
    const tx = this.db.transaction(STORES.STRIKE_AGGREGATES, "readwrite");
    const store = tx.objectStore(STORES.STRIKE_AGGREGATES);
