function drawSparkline(canvas, data, lineColor, fillColor) {
  const ctx = canvas.getContext("2d");
  if (!ctx || data.points.length < 2) return;
  const w = canvas.offsetWidth;
  const h = canvas.offsetHeight;
  const pad = 2;
  const {
    min,
    max
  } = minMax(data.points);
  const n = data.points.length;
  const xStep = (w - pad * 2) / (n - 1);
  const yScale = (h - pad * 2) / (max - min);
  const toX = i => pad + i * xStep;
  const toY = v => pad + (max - v) * yScale;

  // Fill area under line
  ctx.beginPath();
  ctx.moveTo(toX(0), h);
  for (let i = 0; i < n; i++) {
    ctx.lineTo(toX(i), toY(data.points[i]));
  }
  ctx.lineTo(toX(n - 1), h);
  ctx.closePath();
  ctx.fillStyle = fillColor;
  ctx.fill();

  // Line
  ctx.beginPath();
  ctx.moveTo(toX(0), toY(data.points[0]));
  for (let i = 1; i < n; i++) {
    ctx.lineTo(toX(i), toY(data.points[i]));
  }
  ctx.strokeStyle = lineColor;
  ctx.lineWidth = 1.5;
  ctx.lineJoin = "round";
  ctx.stroke();

  // Current value dot
  const ci = data.currentIdx;
  if (ci >= 0 && ci < n) {
    ctx.beginPath();
    ctx.arc(toX(ci), toY(data.points[ci]), 2.5, 0, Math.PI * 2);
    ctx.fillStyle = lineColor;
    ctx.fill();
  }
}
