function createReferenceLinePlugin(value, scaleId = "y", style) {
  const color = style?.color ?? (isDarkTheme() ? "rgba(255,255,255,0.35)" : "rgba(0,0,0,0.3)");
  const dash = style?.dash ?? [4, 3];
  const lineWidth = style?.lineWidth ?? 1;
  return {
    id: `refLine_${scaleId}_${value}`,
    afterDraw: chart => {
      const scale = chart.scales[scaleId];
      if (!scale) return;
      const yPixel = scale.getPixelForValue(value);
      if (yPixel < chart.chartArea.top || yPixel > chart.chartArea.bottom) return;
      const ctx = chart.ctx;
      ctx.save();
      ctx.strokeStyle = color;
      ctx.lineWidth = lineWidth;
      ctx.setLineDash(dash);
      ctx.beginPath();
      ctx.moveTo(chart.chartArea.left, yPixel);
      ctx.lineTo(chart.chartArea.right, yPixel);
      ctx.stroke();
      ctx.restore();
    }
  };
}
