const PCRatioMomentum_PROFILE = FLOW_CHART_PROFILES.pcRatioMomentum;

// ── Helpers ─────────────────────────────────────────────────────────────────

/** Deduplicate to one snapshot per date (last captured). */
function toDailySeries(history) {
  const byDate = new Map();
  for (const snap of history) {
    const date = snap.capturedAt.substring(0, 10);
    const existing = byDate.get(date);
    if (!existing || existing.capturedAt < snap.capturedAt) {
      byDate.set(date, snap);
    }
  }
  return Array.from(byDate.entries()).sort(([a], [b]) => a.localeCompare(b)).map(([date, snap]) => ({
    date,
    pcVolume: snap.pcRatioVolume,
    pcOI: snap.pcRatioOI
  }));
}

/** Simple moving average, preserving null for the leading window. */
function PCRatioMomentum_sma(values, window) {
  const result = [];
  for (let i = 0; i < values.length; i++) {
    if (i < window - 1) {
      result.push(null);
      continue;
    }
    let sum = 0;
    let count = 0;
    for (let j = i - window + 1; j <= i; j++) {
      const v = values[j];
      if (v != null) {
        sum += v;
        count++;
      }
    }
    result.push(count >= window * 0.6 ? sum / count : null);
  }
  return result;
}

