const ImpliedVsRealized_PROFILE = FLOW_CHART_PROFILES.impliedVsRealized;

// ── Helpers ─────────────────────────────────────────────────────────────────

function ImpliedVsRealized_toDailySeries(history) {
  const byDate = new Map();
  for (const snap of history) {
    const date = snap.capturedAt.substring(0, 10);
    const existing = byDate.get(date);
    if (!existing || existing.capturedAt < snap.capturedAt) {
      byDate.set(date, snap);
    }
  }
  return Array.from(byDate.entries()).sort(([a], [b]) => a.localeCompare(b)).map(([date, snap]) => ({
    date,
    impliedMovePct: snap.impliedMovePct,
    price: snap.underlyingPrice
  }));
}
function computeCalibration(daily, lookforward) {
  const points = [];
  // For each date, compare impliedMovePct with actual realized move over lookforward days
  for (let i = 0; i < daily.length - lookforward; i++) {
    const snap = daily[i];
    const futureSnap = daily[i + lookforward];
    if (snap.impliedMovePct == null || snap.price == null || futureSnap.price == null || snap.price === 0) {
      continue;
    }
    const realizedPct = Math.abs((futureSnap.price - snap.price) / snap.price) * 100;
    const impliedPct = Math.abs(snap.impliedMovePct);
    if (impliedPct === 0) continue;
    points.push({
      date: snap.date,
      impliedPct,
      realizedPct,
      ratio: realizedPct / impliedPct
    });
  }
  return points;
}

