function selectOIMatrix(data, type) {
  switch (type) {
    case "call":
      return data.callOIMatrix;
    case "put":
      return data.putOIMatrix;
    default:
      return data.callOIMatrix.map((row, ri) => row.map((v, ci) => v + (data.putOIMatrix[ri]?.[ci] ?? 0)));
  }
}
function formatOI(v) {
  const abs = Math.abs(v);
  if (abs >= 1e6) return `${(v / 1e6).toFixed(1)}M`;
  if (abs >= 1e3) return `${(v / 1e3).toFixed(0)}K`;
  return v.toFixed(0);
}

