  if (rank >= 90) severity = "alert";else if (rank >= 75) severity = "bearish";else if (rank <= 10) severity = "alert";else if (rank <= 25) severity = "bullish";
  let context;
  if (rank >= 90) context = "Extreme high \u2014 sell vol zone";else if (rank >= 75) context = "Elevated IV";else if (rank <= 10) context = "Extreme low \u2014 buy vol zone";else if (rank <= 25) context = "Depressed IV";else context = "Normal range";
  return {
    id,
    label,
    value: `${signalEngine_fmtPct(rank, 0)} (IV ${signalEngine_fmtPct(currentIV, 1)})`,
    detail: `${context} \u00B7 ${ivValues.length}d history`,
    severity,
    chartData: {
      kind: "sparkline",
      points: ivValues,
      currentIdx: ivValues.length - 1,
      percentile: rank
    }
  };
