  let context;
  if (rank >= 95) context = "Extreme call skew \u2014 breakout signal";else if (rank <= 5) context = "Extreme put skew \u2014 fear signal";else if (rank >= 85) context = "Elevated call premium";else if (rank <= 15) context = "Elevated put premium";else context = "Normal skew";
