const AIService_log = logService.namespace("ai");
class AIService {
  orchestrator = null;
  _isRunning = false;
  currentState = null;
  lastRecord = null;
  listeners = new Set();
  streamListeners = new Set();

  /** Subscribe to state updates and replay the current in-progress state. */
  subscribe(listener) {
    this.listeners.add(listener);
    if (this.currentState) {
      listener(this.currentState);
    }
    return () => {
      this.listeners.delete(listener);
    };
  }

  /** Subscribe to streaming token events (text, thinking, annotations). */
  subscribeStream(listener) {
    this.streamListeners.add(listener);
    return () => {
      this.streamListeners.delete(listener);
    };
  }
  isRunning() {
    return this._isRunning;
  }
  getLastRecord() {
    return this.lastRecord;
  }
  getState() {
    return this.currentState;
  }

  /** Start a new analysis run. Throws if another run is already active. */
  async run(symbol, config, deps) {
    if (this._isRunning) {
      throw new Error("An analysis is already in progress. Cancel it first.");
    }
    AIService_log.info("analysis.start", {
      symbol
    });
    this.orchestrator = new AIOrchestrator({
      clients: deps.clients,
      fetcher: deps.fetcher,
      store: deps.store,
      memoryStore: deps.memoryStore
    });
    this._isRunning = true;
    this.currentState = null;
    try {
      const record = await this.orchestrator.runPipeline(symbol, state => {
        this.currentState = state;
        this.listeners.forEach(fn => fn(state));
      }, config,
      // Forward stream events to all stream listeners
      event => {
        this.streamListeners.forEach(fn => {
          try {
            fn(event);
          } catch {
            /* listener error must not break other listeners */
          }
        });
      });
      this.lastRecord = record;
      AIService_log.info("analysis.done", {
        symbol,
        tokensUsed: record.totalTokensUsed
      });
      return record;
    } catch (err) {
      AIService_log.error("analysis.fail", {
        symbol,
        error: err?.message ?? String(err)
      });
      throw err;
    } finally {
      this._isRunning = false;
      this.orchestrator = null;
    }
  }
  cancel() {
    if (this.orchestrator) {
      AIService_log.info("analysis.cancel");
    }
    this.orchestrator?.cancel();
  }
  reset() {
    this.cancel();
    this.currentState = null;
    this.lastRecord = null;
    AIService_log.debug("analysis.reset");
  }
}
const aiService = new AIService();
