function resolvePricing(model, openAIPricingTier = "standard") {
  const openai = OPENAI_MODEL_PRICING_BY_TIER[model];
  if (openai) {
    if (openAIPricingTier === "flex" && openai.flex) return openai.flex;
    if (openAIPricingTier === "batch" && openai.batch) return openai.batch;
    return openai.standard;
  }
  return MODEL_PRICING[model];
}
function costForTokens(model, inputTokens, outputTokens, openAIPricingTier = "standard") {
  const pricing = resolvePricing(model, openAIPricingTier);
  if (!pricing) return 0;
  return inputTokens / 1_000_000 * pricing.input + outputTokens / 1_000_000 * pricing.output;
}
function estimateCost(params) {
  const {
    numAnalysts,
    debateRounds,
    riskRounds,
    analystModel,
    debateModel,
    traderModel,
    riskModel,
    analystOpenAIPricingTier = "standard",
    debateOpenAIPricingTier = "standard",
    traderOpenAIPricingTier = "standard",
    riskOpenAIPricingTier = "standard"
  } = params;
  let total = 0;

  // Phase 1: Analysts
  total += numAnalysts * costForTokens(analystModel, STAGE_TOKENS.analyst.input, STAGE_TOKENS.analyst.output, analystOpenAIPricingTier);

  // Phase 2: Debate rounds (2 debaters + 1 research manager per round)
  total += debateRounds * (2 * costForTokens(debateModel, STAGE_TOKENS.debater.input, STAGE_TOKENS.debater.output, debateOpenAIPricingTier) + costForTokens(debateModel, STAGE_TOKENS.researchMgr.input, STAGE_TOKENS.researchMgr.output, debateOpenAIPricingTier));

  // Phase 3: Trader
  total += costForTokens(traderModel, STAGE_TOKENS.trader.input, STAGE_TOKENS.trader.output, traderOpenAIPricingTier);

  // Phase 4: Risk (3 analysts per round + 1 risk manager at end)
  total += riskRounds * 3 * costForTokens(riskModel, STAGE_TOKENS.riskAnalyst.input, STAGE_TOKENS.riskAnalyst.output, riskOpenAIPricingTier);
  total += costForTokens(riskModel, STAGE_TOKENS.riskManager.input, STAGE_TOKENS.riskManager.output, riskOpenAIPricingTier);
  return total;
}
