// ── Citation list helper ─────────────────────────────────────────────────────

function buildCitationList(citations) {
  const seen = new Set();
  const unique = [];
  for (const c of citations) {
    if (!seen.has(c.url)) {
      seen.add(c.url);
      unique.push({
        ...c,
        index: unique.length + 1
      });
    }
  }
  const list = createElement_ui_createElement("div", {
    className: "ai-citation-list"
  });
  list.appendChild(createElement_ui_createElement("div", {
    text: "Sources",
    styleString: "font-size: 10px; font-weight: 700; color: var(--ios-text-secondary); text-transform: uppercase; letter-spacing: 0.3px; margin-bottom: 2px;"
  }));
  for (const c of unique) {
    const a = document.createElement("a");
    a.href = c.url;
    a.target = "_blank";
    a.rel = "noopener noreferrer";
    a.textContent = `[${c.index}] ${c.title || c.url}`;
    list.appendChild(a);
  }
  return list;
}
