// ── Types ────────────────────────────────────────────────────────────────────

// ── Factory ──────────────────────────────────────────────────────────────────

function createConnectivitySection(opts) {
  const {
    selectedProvider,
    getCustomModels,
    resolveClientConfig,
    getStoredKeyForProvider
  } = opts;
  const {
    settingFieldInput: fieldInputStyle
  } = theme_DS_COMPONENTS;
  const MODEL_OPTIONS = modelCatalog_BUILTIN_MODEL_OPTIONS;
  const connectivitySection = createSettingsSectionCard("Connectivity");
  const testResultsEl = createElement_ui_createElement("div", {
    styleString: "display: none; flex-direction: column; gap: 4px; max-height: 200px; overflow-y: auto; padding: 0 16px 8px;"
  });
  const singleTestSelect = createElement_ui_createElement("select", {
    styleString: fieldInputStyle + " width: 100%; box-sizing: border-box;"
  });
  const renderTestModelDropdown = () => {
    const provider = selectedProvider();
    singleTestSelect.innerHTML = "";
    for (const opt of MODEL_OPTIONS[provider]) {
      const el = document.createElement("option");
      el.value = opt.value;
      el.textContent = `${opt.value} (${opt.hint})`;
      singleTestSelect.appendChild(el);
    }
    for (const profile of getCustomModels()) {
      if (profile.provider !== provider) continue;
      const el = document.createElement("option");
      el.value = profile.id;
      el.textContent = `${profile.model} (${profile.name})`;
      singleTestSelect.appendChild(el);
    }
  };
  const testAllBtn = createSettingsActionButton("Test All", {
    width: 84
  });
  const testSingleBtn = createSettingsActionButton("Test", {
    width: 60
  });
  appendSettingsMatrixRow({
    body: connectivitySection.body,
    label: "",
    toggleEl: testAllBtn,
    paramLabel: "test",
    controlEl: createElement_ui_createElement("div", {
      styleString: "display: flex; align-items: center; gap: 4px;",
      children: [singleTestSelect, testSingleBtn]
    })
  });
  connectivitySection.section.appendChild(testResultsEl);
  const runModelTest = async (_label, testConfig, statusSpan, detailSpan) => {
    if (!testConfig.apiKey) {
      statusSpan.textContent = "\u2717";
      statusSpan.style.color = "var(--ios-red)";
      detailSpan.textContent = "No API key";
      return;
    }
    try {
      const client = new LLMClient(testConfig);
      const start = Date.now();
      const resp = await client.complete({
        systemPrompt: "You are a test assistant.",
        messages: [{
          role: "user",
          content: "Hello"
        }],
        maxTokens: 20,
        temperature: 0
      });
      const elapsed = ((Date.now() - start) / 1000).toFixed(1);
      statusSpan.textContent = "\u2713";
      statusSpan.style.color = "var(--ios-green)";
      detailSpan.textContent = `OK \u00b7 ${elapsed}s \u00b7 ${resp.tokensUsed} tok`;
    } catch (err) {
      statusSpan.textContent = "\u2717";
      statusSpan.style.color = "var(--ios-red)";
      detailSpan.textContent = err instanceof Error ? err.message.slice(0, 60) : "Error";
    }
  };
  const createTestResultRow = label => {
    const row = createElement_ui_createElement("div", {
      styleString: "display: flex; align-items: center; gap: 6px; font-size: 11px;"
    });
    const statusSpan = createElement_ui_createElement("span", {
      text: "\u23f3",
      styleString: "flex-shrink: 0; width: 14px; text-align: center;"
    });
    row.appendChild(statusSpan);
    row.appendChild(createElement_ui_createElement("span", {
      text: label,
      styleString: "color: var(--ios-text-primary); flex: 1; min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;"
    }));
    const detailSpan = createElement_ui_createElement("span", {
      text: "testing\u2026",
      styleString: "color: var(--ios-text-secondary); white-space: nowrap;"
    });
    row.appendChild(detailSpan);
    return {
      row,
      statusSpan,
      detailSpan
    };
  };
  testAllBtn.addEventListener("click", async e => {
    e.preventDefault();
    testAllBtn.disabled = true;
    testAllBtn.textContent = "Testing\u2026";
    testResultsEl.innerHTML = "";
    testResultsEl.style.display = "flex";
    const provider = selectedProvider();
    const modelsToTest = [];
    for (const opt of MODEL_OPTIONS[provider]) {
      modelsToTest.push({
        label: `${opt.value} (${opt.hint})`,
        config: {
          provider,
          apiKey: getStoredKeyForProvider(provider),
          model: opt.value,
          maxTokens: 20,
          openAIServiceTier: "auto"
        }
      });
    }
    for (const profile of getCustomModels()) {
      if (profile.provider !== provider) continue;
      modelsToTest.push({
        label: `${profile.model} (${profile.name})`,
        config: resolveClientConfig(profile.id)
      });
    }
    for (const entry of modelsToTest) {
      const {
        row,
        statusSpan,
        detailSpan
      } = createTestResultRow(entry.label);
      testResultsEl.appendChild(row);
      await runModelTest(entry.label, entry.config, statusSpan, detailSpan);
    }
    testAllBtn.disabled = false;
    testAllBtn.textContent = "Test All";
  });
  testSingleBtn.addEventListener("click", async e => {
    e.preventDefault();
    const profileId = singleTestSelect.value;
    if (!profileId) return;
    testSingleBtn.disabled = true;
    testSingleBtn.textContent = "\u2026";
    testResultsEl.innerHTML = "";
    testResultsEl.style.display = "flex";
    const testConfig = resolveClientConfig(profileId);
    const {
      row,
      statusSpan,
      detailSpan
    } = createTestResultRow(profileId);
    testResultsEl.appendChild(row);
    await runModelTest(profileId, testConfig, statusSpan, detailSpan);
    testSingleBtn.disabled = false;
    testSingleBtn.textContent = "Test";
  });

  // Initial render
  renderTestModelDropdown();
  return {
    section: connectivitySection.section,
    refreshDropdown: renderTestModelDropdown
  };
}
;// ./src/frontend/analysis_ai/setting_panel/providerSection.ts



// ── Constants ────────────────────────────────────────────────────────────────

const providerSection_PROVIDER_OPTIONS = [{
  value: "anthropic",
  label: "Anthropic (Claude)"
}, {
  value: "openai",
  label: "OpenAI (ChatGPT)"
}, {
  value: "google",
  label: "Google (Gemini)"
}];

// ── Types ────────────────────────────────────────────────────────────────────

// ── Factory ──────────────────────────────────────────────────────────────────

function createProviderSection(opts) {
  const {
    config,
    configStore,
    selectedProvider
  } = opts;
  const {
    settingFieldInput: fieldInputStyle
  } = theme_DS_COMPONENTS;
  const getStoredKeyForProvider = p => {
    if (p === "anthropic") return config.providers.anthropic.apiKey;
    if (p === "openai") return config.providers.openai.apiKey;
    return config.providers.google.apiKey;
  };
  const providerSection = createSettingsSectionCard("Provider");
  const providerSelect = createElement_ui_createElement("select", {
    styleString: fieldInputStyle + " width: 100%; box-sizing: border-box;"
  });
  for (const p of providerSection_PROVIDER_OPTIONS) {
    const opt = document.createElement("option");
    opt.value = p.value;
    opt.textContent = p.label;
    if (p.value === selectedProvider) opt.selected = true;
    providerSelect.appendChild(opt);
  }
  const apiKeyInput = createElement_ui_createElement("input", {
    props: {
      type: "password",
      value: getStoredKeyForProvider(selectedProvider),
      placeholder: "Enter API key"
    },
    styleString: fieldInputStyle + " width: 100%; box-sizing: border-box;"
  });
  appendSettingsMatrixRow({
    body: providerSection.body,
    label: "Provider",
    toggleEl: providerSelect,
    paramLabel: "API Key",
    controlEl: apiKeyInput
  });
  const wireEvents = evtOpts => {
    providerSelect.addEventListener("change", () => {
      evtOpts.onProviderChange(providerSelect.value);
    });
    apiKeyInput.addEventListener("blur", () => {
      const trimmedKey = apiKeyInput.value.trim();
      const prov = providerSelect.value;
      if (prov === "anthropic") config.providers.anthropic.apiKey = trimmedKey;else if (prov === "openai") config.providers.openai.apiKey = trimmedKey;else config.providers.google.apiKey = trimmedKey;
      void configStore.save("providers", {
        ...config.providers
      });
      evtOpts.onApiKeyBlur();
    });
  };
  return {
    section: providerSection.section,
    providerSelect,
    apiKeyInput,
    getStoredKeyForProvider,
    wireEvents
  };
}
;// ./src/frontend/analysis_ai/setting_panel/modelSection.ts






// ── Constants ────────────────────────────────────────────────────────────────

const MODEL_OPTIONS = modelCatalog_BUILTIN_MODEL_OPTIONS;
const SERVICE_TIER_LABELS = {
  auto: "Auto",
  default: "Default",
  flex: "Flex (cheaper, slower)",
  priority: "Priority (faster)"
};

// ── Helpers ──────────────────────────────────────────────────────────────────

const parseIntBounded = (raw, fallback, min, max) => {
  const n = parseInt(raw, 10);
  return Number.isNaN(n) ? fallback : Math.min(max, Math.max(min, n));
};
const parseFloatBounded = (raw, fallback, min, max) => {
  const n = parseFloat(raw);
  return Number.isNaN(n) ? fallback : Math.min(max, Math.max(min, n));
};

// ── Types ────────────────────────────────────────────────────────────────────

// ── Factory ──────────────────────────────────────────────────────────────────

function createModelSection(opts) {
  const {
    config,
    configStore,
    selectedProvider,
    getCustomModels,
    allBuiltinModels
  } = opts;
  const {
    settingFieldInput: fieldInputStyle
  } = theme_DS_COMPONENTS;

  // ── Pricing helpers ─────────────────────────────────────────────────────

  const getEffectivePricingForOpenAIModel = (model, isCustom, profileServiceTier) => {
    const preferred = profileServiceTier ?? config.providers.openai.serviceTier;
    const effective = resolveEffectiveOpenAIServiceTier(model, preferred, isCustom);
    return derivePricingTierFromServiceTier(effective);
  };
  const getModelPriceLabel = (provider, model, profile) => {
    if (provider !== "openai") return formatPrice(model);
    const pricingTier = getEffectivePricingForOpenAIModel(model, Boolean(profile), profile?.openAIServiceTier);
    return formatPrice(model, pricingTier);
  };

  // ── Resolve current model ────────────────────────────────────────────────

  let _getSelectedModelProfileId = () => "";
  const resolveCurrentSelectedModel = () => {
    const selectedModelProfileId = _getSelectedModelProfileId();
    const profile = getCustomModels().find(m => m.id === selectedModelProfileId);
    if (profile) return {
      provider: profile.provider,
      model: profile.model,
      isCustom: true,
      profile
    };
    const builtin = allBuiltinModels.find(m => m.value === selectedModelProfileId);
    if (builtin) return {
      provider: builtin.provider,
      model: builtin.value,
      isCustom: false
    };
    return {
      provider: selectedProvider(),
      model: MODEL_OPTIONS[selectedProvider()][0].value,
      isCustom: false
    };
  };

  // ── Model dropdown ─────────────────────────────────────────────────────

  const modelSelect = createElement_ui_createElement("select", {
    styleString: fieldInputStyle + " width: 100%; box-sizing: border-box;"
  });
  const modelDescriptionEl = createElement_ui_createElement("div", {
    text: "",
    styleString: "font-size: 11px; color: var(--ios-text-secondary); padding: 2px 0 4px 0; grid-column: 1 / -1;"
  });
  const updateModelDescription = () => {
    const selected = resolveCurrentSelectedModel();
    const details = [];
    const builtin = MODEL_OPTIONS[selected.provider].find(m => m.value === selected.model);
    if (builtin) {
      details.push(builtin.hint);
      if (builtin.maxOutputTokens) details.push(`${builtin.maxOutputTokens / 1000}K max output`);
      details.push(builtin.supportsCustomTemperature === false ? "Fixed temp" : "Custom temp");
    } else if (selected.profile) {
      details.push(selected.profile.name);
    }
    const price = getModelPriceLabel(selected.provider, selected.model, selected.profile);
    if (price) details.push(price);
    modelDescriptionEl.textContent = details.join(" \u00b7 ");
  };
  const renderModelDropdown = (provider, currentProfileId) => {
    modelSelect.innerHTML = "";
    for (const opt of MODEL_OPTIONS[provider]) {
      const el = document.createElement("option");
      el.value = opt.value;
      el.textContent = opt.value;
      if (opt.value === currentProfileId) el.selected = true;
      modelSelect.appendChild(el);
    }
    for (const profile of getCustomModels()) {
      if (profile.provider !== provider) continue;
      const el = document.createElement("option");
      el.value = profile.id;
      el.textContent = `${profile.model} (${profile.name})`;
      if (profile.id === currentProfileId) el.selected = true;
      modelSelect.appendChild(el);
    }
    updateModelDescription();
  };

  // ── Controls wrapper ───────────────────────────────────────────────────

  const controlsWrapper = createElement_ui_createElement("div", {
    styleString: "display: contents;"
  });

  // Model row
  const tempFormRow = createElement_ui_createElement("div", {
    styleString: "display: contents;"
  });
  appendSettingsFormRow({
    body: tempFormRow,
    label: "Model",
    controlEl: modelSelect
  });
  controlsWrapper.appendChild(tempFormRow);
  controlsWrapper.appendChild(modelDescriptionEl);

  // Service Tier + Max Tokens row
  const serviceTierSelect = createElement_ui_createElement("select", {
    styleString: fieldInputStyle + " width: 100%; box-sizing: border-box;"
  });
  const maxTokensInput = createElement_ui_createElement("input", {
    props: {
      type: "number",
      value: config.general.maxTokens.toString(),
      min: 100
    },
    styleString: fieldInputStyle + " width: 10ch;"
  });
  const serviceTierContainer = createElement_ui_createElement("div", {
    styleString: "display: flex; align-items: center; gap: 4px;",
    children: [serviceTierSelect]
  });
  const maxTokensContainer = createElement_ui_createElement("div", {
    styleString: "display: inline-flex; align-items: center; gap: 4px;",
    children: [maxTokensInput, createElement_ui_createElement("span", {
      text: "tokens",
      styleString: "font-size: 12px; color: var(--ios-text-secondary);"
    })]
  });
  const tempMatrixRow = createElement_ui_createElement("div", {
    styleString: "display: contents;"
  });
  appendSettingsMatrixRow({
    body: tempMatrixRow,
    label: "Service tier",
    toggleEl: serviceTierContainer,
    paramLabel: "Max tokens",
    controlEl: maxTokensContainer
  });
  controlsWrapper.appendChild(tempMatrixRow);
  const syncServiceTierDropdown = () => {
    const isOpenAI = selectedProvider() === "openai";
    serviceTierSelect.disabled = !isOpenAI;
    serviceTierSelect.style.opacity = isOpenAI ? "1" : "0.45";
    if (!isOpenAI) {
      serviceTierSelect.innerHTML = "";
      const na = document.createElement("option");
      na.textContent = "N/A";
      serviceTierSelect.appendChild(na);
      return;
    }
    const selected = resolveCurrentSelectedModel();
    const model = selected.provider === "openai" ? selected.model : MODEL_OPTIONS.openai[0].value;
    const isCustom = selected.provider === "openai" ? selected.isCustom : false;
    const tiers = getSupportedOpenAIServiceTiers(model, isCustom);
    const effective = resolveEffectiveOpenAIServiceTier(model, config.providers.openai.serviceTier, isCustom);
    serviceTierSelect.innerHTML = "";
    for (const tier of tiers) {
      const opt = document.createElement("option");
      opt.value = tier;
      opt.textContent = SERVICE_TIER_LABELS[tier];
      if (tier === effective) opt.selected = true;
      serviceTierSelect.appendChild(opt);
    }
  };

  // Temperature row
  const temperatureInput = createElement_ui_createElement("input", {
    props: {
      type: "number",
      value: config.general.temperature.toString(),
      min: 0,
      max: 1,
      step: 0.1
    },
    styleString: fieldInputStyle + " width: 10ch;"
  });
  const temperatureContainer = createElement_ui_createElement("div", {
    styleString: "display: inline-flex; align-items: center; gap: 4px;",
    children: [temperatureInput, createElement_ui_createElement("span", {
      text: "0\u20131",
      styleString: "font-size: 12px; color: var(--ios-text-secondary);"
    })]
  });
  const tempTempRow = createElement_ui_createElement("div", {
    styleString: "display: contents;"
  });
  appendSettingsFormRow({
    body: tempTempRow,
    label: "Temperature",
    controlEl: temperatureContainer
  });
  controlsWrapper.appendChild(tempTempRow);
  const syncTemperatureField = () => {
    const selected = resolveCurrentSelectedModel();
    const canCustomize = supportsCustomTemperature(selected.provider, selected.model);
    temperatureInput.disabled = !canCustomize;
    temperatureInput.style.opacity = canCustomize ? "1" : "0.55";
  };

  // ── Wire events ────────────────────────────────────────────────────────

  const wireEvents = evtOpts => {
    _getSelectedModelProfileId = evtOpts.getSelectedModelProfileId;
    modelSelect.addEventListener("change", () => {
      evtOpts.setSelectedModelProfileId(modelSelect.value);
      evtOpts.persistSelectedModel();
      updateModelDescription();
      syncServiceTierDropdown();
      syncTemperatureField();
    });
    maxTokensInput.addEventListener("blur", () => {
      const selected = resolveCurrentSelectedModel();
      const requested = parseIntBounded(maxTokensInput.value, config.general.maxTokens, 100, 64000);
      const capped = clampMaxTokensForModel(selected.provider, selected.model, requested);
      config.general.maxTokens = capped;
      maxTokensInput.value = String(capped);
      void configStore.save("general", {
        ...config.general
      });
    });
    temperatureInput.addEventListener("blur", () => {
      if (temperatureInput.disabled) return;
      config.general.temperature = parseFloatBounded(temperatureInput.value, config.general.temperature, 0, 1);
      void configStore.save("general", {
        ...config.general
      });
    });
    serviceTierSelect.addEventListener("change", () => {
      const tier = OPENAI_SERVICE_TIER_OPTIONS.includes(serviceTierSelect.value) ? serviceTierSelect.value : "auto";
      config.providers.openai.serviceTier = tier;
      config.providers.openai.pricingTier = derivePricingTierFromServiceTier(tier);
      syncServiceTierDropdown();
      renderModelDropdown(evtOpts.getSelectedProvider(), evtOpts.getSelectedModelProfileId());
      evtOpts.refreshCustomModels();
      evtOpts.notifyChange();
      void configStore.save("providers", {
        ...config.providers
      });
    });
  };
  return {
    controlsWrapper,
    modelSelect,
    renderModelDropdown,
    syncServiceTierDropdown,
    syncTemperatureField,
    resolveCurrentSelectedModel,
    getEffectivePricingForOpenAIModel,
    getModelPriceLabel,
    wireEvents
  };
}
