// ── Types ────────────────────────────────────────────────────────────────────

// ── Constants ────────────────────────────────────────────────────────────────

const PHASE_ORDER = ["fetching_data", "running_analysts", "running_debate", "running_trader", "running_risk", "finalizing"];

// ── Helpers ──────────────────────────────────────────────────────────────────

function getNodeStatus(node, state) {
  if (!state || state.phase === "idle") return "pending";
  if (state.phase === "complete") return "done";
  if (state.phase === "error") {
    const currentIdx = PHASE_ORDER.indexOf(state.phase);
    const nodeIdx = Math.min(...node.phaseMatch.map(p => PHASE_ORDER.indexOf(p)).filter(i => i >= 0));
    if (nodeIdx <= currentIdx) return "error";
    return "pending";
  }
  const currentIdx = PHASE_ORDER.indexOf(state.phase);
  const nodeMinIdx = Math.min(...node.phaseMatch.map(p => {
    const i = PHASE_ORDER.indexOf(p);
    return i >= 0 ? i : Infinity;
  }));
  if (nodeMinIdx === Infinity) return "pending";
  if (currentIdx > nodeMinIdx) return "done";
  if (node.phaseMatch.includes(state.phase)) return "running";
  return "pending";
}
function nodeChipStyle(status) {
  const base = "padding: 6px 12px; border-radius: 8px; font-size: 12px; font-weight: 600;" + " white-space: nowrap; transition: all 0.3s; border: 1.5px solid; user-select: none;";
  switch (status) {
    case "pending":
      return base + " background: var(--ax-bg-glass-inset); color: var(--ios-text-secondary); border-color: var(--ios-border); cursor: default;";
    case "running":
      return base + " background: rgba(0,122,255,0.12); color: var(--ios-blue); border-color: rgba(0,122,255,0.3); cursor: default;";
    case "done":
      return base + " background: rgba(52,199,89,0.10); color: var(--ios-green); border-color: rgba(52,199,89,0.3); cursor: pointer;";
    case "error":
      return base + " background: rgba(255,59,48,0.10); color: var(--ios-red); border-color: rgba(255,59,48,0.3); cursor: pointer;";
  }
}

