    data,
    xLabel,
    yLabel,
    xFormatter = v => formatters_formatCurrencyLocale(v, 0),
    yFormatter = v => formatPct(v, {
      decimals: 2
    }),
    sizeLabel = "Market Value",
    sizeFormatter = v => formatters_formatCurrencyLocale(v, 0),
    colorize = p => p.x >= 0 ? CHART_COLORS.success : CHART_COLORS.danger,
