const KV_WATCHLIST_KEY = "ui.movingBetaWatchlist";
const KV_INDICATORS_KEY = "ui.movingBetaIndicators";
const DEFAULT_INDICATORS = ["$SPX", "$COMPX", "$DJI"];
async function loadMovingBetaAxes(defaultSymbols) {
  const db = await openAlexQuantDB();
  const kv = new KVStore(db);
  const watchlist = await kv.get(KV_WATCHLIST_KEY);
  const indicators = await kv.get(KV_INDICATORS_KEY);
  return {
    watchlist: watchlist && watchlist.length > 0 ? watchlist : [...defaultSymbols],
    indicators: indicators && indicators.length > 0 ? indicators : [...DEFAULT_INDICATORS]
  };
}
function saveMovingBetaAxes(watchlistTickers, indicatorTickers) {
  openAlexQuantDB().then(db => {
    const kv = new KVStore(db);
    return Promise.all([kv.set(KV_WATCHLIST_KEY, watchlistTickers), kv.set(KV_INDICATORS_KEY, indicatorTickers)]);
  }).catch(() => {
    /* noop */
  });
}
